/**
 * Provenance of the message. `concierge_draft` marks notes the
AI concierge drafted that the sender confirmed and sent via
`POST /concierge/send-draft`; the inbox renders a small
"drafted with concierge" badge for these so the recipient
knows the wording came from the assistant. `team_up_note`
marks the requester's personal note that was carried into
the new direct-message thread when a team-up request was
accepted (#599) — the inbox renders it as a centered, quoted
opener so both sides see the original reason for the
connection. `system_connected` is a system-authored note
inserted at accept time (#603) so the freshly-unlocked
thread opens with a "you're now connected" anchor instead
of a blank composer. `team_up_request` is a system-authored
note dropped into both inboxes the moment a team-up request
is sent (#656) — the chat renders it as a centered system
pill ("Asked to team up as Collaborator", followed by the
optional personal note) so the requester has a thread row
to look at and the recipient sees the request from the
inbox surface they already check. NULL / `user` means a
regular DM the sender typed themselves.

 */
export type MessageItemSource =
  | (typeof MessageItemSource)[keyof typeof MessageItemSource]
  | null;

export const MessageItemSource = {
  user: "user",
  concierge_draft: "concierge_draft",
  team_up_note: "team_up_note",
  system_connected: "system_connected",
  team_up_request: "team_up_request",
} as const;

export interface MessageItem {
  id: number;
  senderClerkId: string;
  recipientClerkId?: string | null;
  propertyId?: number | null;
  content: string;
  isRead: boolean;
  createdAt: string;
  /** Provenance of the message. `concierge_draft` marks notes the
AI concierge drafted that the sender confirmed and sent via
`POST /concierge/send-draft`; the inbox renders a small
"drafted with concierge" badge for these so the recipient
knows the wording came from the assistant. `team_up_note`
marks the requester's personal note that was carried into
the new direct-message thread when a team-up request was
accepted (#599) — the inbox renders it as a centered, quoted
opener so both sides see the original reason for the
connection. `system_connected` is a system-authored note
inserted at accept time (#603) so the freshly-unlocked
thread opens with a "you're now connected" anchor instead
of a blank composer. `team_up_request` is a system-authored
note dropped into both inboxes the moment a team-up request
is sent (#656) — the chat renders it as a centered system
pill ("Asked to team up as Collaborator", followed by the
optional personal note) so the requester has a thread row
to look at and the recipient sees the request from the
inbox surface they already check. NULL / `user` means a
regular DM the sender typed themselves.
 */
  source?: MessageItemSource;
  sender: UserProfile;
}

export interface Conversation {
  otherUser: UserProfile;
  /** Stable outward-account id of the other side of the
conversation. The inbox row deep-links to
`/inbox/{otherOutwardAccountId}` when present so the
messaging endpoint resolves the *exact* skin pair the
connection was accepted on (matches Task #597's Open chat
shortcut). Null only on legacy pre-#307 rows where the
outward account columns were never backfilled — fall back
to `otherUser.clerkId` in that case.
 */
  otherOutwardAccountId?: number | null;
  lastMessage: MessageItem;
  /** True when this conversation row was synthesized from an
accepted team-up connection that has no messages exchanged
yet (#604). Lets the inbox render a "say hi" placeholder
instead of a real preview line. `lastMessage.content` is an
empty string and `lastMessage.id` is `0` for these synthetic
rows.
 */
  isEmpty?: boolean;
  /** True when there's a still-pending team-up request from the
*other* side targeting the viewer's active outward account
(#656). The inbox uses this to render a "View team-up
request" CTA and route the row tap to `/invites` instead of
opening the gated chat thread, since the recipient can't
reply until they accept the request. Independent of
`isEmpty` — the team-up-request system message is itself a
real message, so the row is never synthetic.
 */
  pendingTeamUpFromOther?: boolean;
  unreadCount: number;
}

export interface ListConversationsResponse {
  conversations: Conversation[];
}

/**
 * Per-thread team-up gate summary used by the client to render the
blocked banner pre-emptively (#644). `self` covers legacy
self-threads (sender == recipient outward account), `connected`
means a usable accepted connection exists in either direction,
and `team_up_required` mirrors the 403 sent by POST /messages.

 */
export type ListMessagesResponseTeamUpStatus =
  (typeof ListMessagesResponseTeamUpStatus)[keyof typeof ListMessagesResponseTeamUpStatus];

export const ListMessagesResponseTeamUpStatus = {
  self: "self",
  connected: "connected",
  team_up_required: "team_up_required",
} as const;

/**
 * From the caller's perspective. `incoming` means the other side
sent the request and the caller can accept/decline; `outgoing`
means the caller sent it and is waiting on the other side.

 */
export type PendingTeamUpInThreadDirection =
  (typeof PendingTeamUpInThreadDirection)[keyof typeof PendingTeamUpInThreadDirection];

export const PendingTeamUpInThreadDirection = {
  incoming: "incoming",
  outgoing: "outgoing",
} as const;

/**
 * #656 — pending `user_connections` row exposed on the inbox thread
so the recipient can see and act on the invite without leaving the
conversation. The card uses `inviteMessage` (the system-composed
first-contact text) as its body and `kind` as the relationship
chip.

 */
export interface PendingTeamUpInThread {
  id: number;
  /** From the caller's perspective. `incoming` means the other side
sent the request and the caller can accept/decline; `outgoing`
means the caller sent it and is waiting on the other side.
 */
  direction: PendingTeamUpInThreadDirection;
  kind: ConnectionKind;
  inviteMessage: string | null;
  personalNote: string | null;
  fromOutwardAccountId: number;
  toOutwardAccountId: number;
  /** Clerk id of the user who originally sent the request. The
client passes this to `POST /users/{userId}/team-up/respond`
(the existing accept/decline endpoint).
 */
  requesterClerkId: string;
  /** The from-side outward-account id, passed back to /respond as
`requesterOutwardAccountId` so the server picks the exact skin
pair when a user has multiple skins with pending requests.
 */
  requesterOutwardAccountId: number;
  requestedAt: string | null;
}

export interface ListMessagesResponse {
  messages: MessageItem[];
  total: number;
  /** Outward-account id of the other side of this thread (null when no addressable target was resolved). */
  otherOutwardAccountId?: number | null;
  /** Whether the caller is currently allowed to send a message in this
thread. False when no accepted, non-archived team-up connection
exists between the caller's active outward account and the target.
 */
  canMessage: boolean;
  /** Per-thread team-up gate summary used by the client to render the
blocked banner pre-emptively (#644). `self` covers legacy
self-threads (sender == recipient outward account), `connected`
means a usable accepted connection exists in either direction,
and `team_up_required` mirrors the 403 sent by POST /messages.
 */
  teamUpStatus: ListMessagesResponseTeamUpStatus;
  /** #656 — when an unaccepted team-up request exists between the
caller's active outward account and the target (in either
direction), this field carries the pending row so the inbox
can surface it as an actionable invite card. Null when no
pending row exists. The card calls
`POST /api/users/{requesterClerkId}/team-up/respond` to accept
or decline; no separate endpoint is introduced.
 */
  pendingTeamUp?: PendingTeamUpInThread | null;
}

